Translate this Go concurrent fan-out pattern to Hemlock. Go's goroutines map to Hemlock's `spawn()`, and Go's channels map to Hemlock's `channel()`.

```go
package main

import (
    "fmt"
    "sync"
)

func worker(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {
    defer wg.Done()
    for job := range jobs {
        result := job * job
        results <- result
    }
}

func main() {
    jobs := make(chan int, 10)
    results := make(chan int, 10)

    var wg sync.WaitGroup
    // Start 3 workers
    for w := 0; w < 3; w++ {
        wg.Add(1)
        go worker(w, jobs, results, &wg)
    }

    // Send 9 jobs
    for j := 1; j <= 9; j++ {
        jobs <- j
    }
    close(jobs)

    // Wait for workers then close results
    go func() {
        wg.Wait()
        close(results)
    }()

    // Collect results
    sum := 0
    count := 0
    for result := range results {
        sum += result
        count++
    }
    fmt.Printf("processed: %d\n", count)
    fmt.Printf("sum: %d\n", sum)
}
```

In Hemlock, there's no WaitGroup - use join() on tasks. Close channels explicitly. The sum of squares 1-9 is 285.
